import{_ as t,o as d,c as r,a2 as a}from"./chunks/framework.DdLJaIXX.js";const u=JSON.parse('{"title":"Skills Reference","description":"","frontmatter":{},"headers":[],"relativePath":"reference/skills.md","filePath":"reference/skills.md"}'),o={name:"reference/skills.md"};function i(s,e,c,n,l,h){return d(),r("div",null,[...e[0]||(e[0]=[a('<h1 id="skills-reference" tabindex="-1">Skills Reference <a class="header-anchor" href="#skills-reference" aria-label="Permalink to &quot;Skills Reference&quot;">​</a></h1><p>Skills are slash commands invoked inside Claude Code. All <strong>42 skills</strong> are embedded in the CQ binary (<code>skills_embed</code> build tag) — no internet required after install.</p><h2 id="ideation" tabindex="-1">Ideation <a class="header-anchor" href="#ideation" aria-label="Permalink to &quot;Ideation&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Skill</th><th>Triggers</th><th>Description</th></tr></thead><tbody><tr><td><code>/pi</code></td><td>play idea, ideation, brainstorm</td><td>Brainstorm and refine ideas before planning. Diverge/converge/research/debate modes. Writes <code>idea.md</code> and auto-launches <code>/plan</code>.</td></tr></tbody></table><h2 id="core-workflow" tabindex="-1">Core Workflow <a class="header-anchor" href="#core-workflow" aria-label="Permalink to &quot;Core Workflow&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Skill</th><th>Triggers</th><th>Description</th></tr></thead><tbody><tr><td><code>/plan</code></td><td>plan, planning, design, blueprint</td><td>Discovery → Design → Lighthouse contracts → Task creation. Full structured plan for a feature.</td></tr><tr><td><code>/run</code></td><td>run, execute, go</td><td>Spawn workers for all pending tasks in parallel. Continuous mode — auto-respawns until queue empty.</td></tr><tr><td><code>/finish</code></td><td>finish, complete, wrap up</td><td>Build → test → docs → commit. Post-implementation completion routine.</td></tr><tr><td><code>/status</code></td><td>status, progress</td><td>Visual task graph with progress, dependency graph, queue summary, and worker status.</td></tr><tr><td><code>/quick</code></td><td>quick, fast</td><td>Create + assign one task immediately, skip planning. For small focused changes.</td></tr></tbody></table><h2 id="quality-loop" tabindex="-1">Quality Loop <a class="header-anchor" href="#quality-loop" aria-label="Permalink to &quot;Quality Loop&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Skill</th><th>Triggers</th><th>Description</th></tr></thead><tbody><tr><td><code>/polish</code></td><td>polish</td><td><em>(Deprecated — polish loop is now built into <code>/finish</code>. No separate invocation needed.)</em></td></tr><tr><td><code>/refine</code></td><td>refine</td><td><em>(Deprecated — quality loop is now built into <code>/finish</code>. No separate invocation needed.)</em></td></tr><tr><td><code>/checkpoint</code></td><td>(auto at checkpoint)</td><td>Phase gate: 4-lens review (holistic / user-flow / cascade / ship-ready). Approve, request changes, replan, or redesign.</td></tr><tr><td><code>/validate</code></td><td>validate, check</td><td>Run lint + tests with severity-based handling. CRITICAL blocks commit, HIGH requires review, MEDIUM is recommended.</td></tr><tr><td><code>/review</code></td><td>review</td><td>Comprehensive 3-pass code or paper review with 6-axis evaluation. Generates formal review document.</td></tr><tr><td><code>/company-review</code></td><td>company review, code review, diff review</td><td>PI Lab standard code review. PR/MR diff-based 6-axis evaluation.</td></tr><tr><td><code>/submit</code></td><td>submit, send</td><td>Submit completed task with automated validation. Verifies commit SHA, triggers checkpoint if needed.</td></tr><tr><td><code>/simplify</code></td><td>simplify, clean up</td><td>Review changed code for reuse, quality, and efficiency, then fix any issues found.</td></tr></tbody></table><h2 id="task-management" tabindex="-1">Task Management <a class="header-anchor" href="#task-management" aria-label="Permalink to &quot;Task Management&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Skill</th><th>Triggers</th><th>Description</th></tr></thead><tbody><tr><td><code>/add-task</code></td><td>add task, new task</td><td>Add task interactively with DoD, scope, and domain guidance. Infers ID from existing patterns.</td></tr><tr><td><code>/stop</code></td><td>stop, halt</td><td>Stop execution, transition to HALTED state. Preserves progress for later resumption.</td></tr><tr><td><code>/swarm</code></td><td>swarm</td><td>Spawn coordinator-led agent team. Modes: standard (implementation), review (read-only audit), investigate (hypothesis competition).</td></tr></tbody></table><h2 id="session" tabindex="-1">Session <a class="header-anchor" href="#session" aria-label="Permalink to &quot;Session&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Skill</th><th>Triggers</th><th>Description</th></tr></thead><tbody><tr><td><code>/done</code></td><td>done, session end, session done</td><td>Mark the current session as done with full capture — summarize work, save knowledge, clean up state.</td></tr><tr><td><code>/attach</code></td><td>session name, attach, name this session</td><td>Attach a name to the current session for later resume with <code>cq claude -t &lt;name&gt;</code>. Optionally add a memo.</td></tr><tr><td><code>/reboot</code></td><td>reboot, restart</td><td>Reboot the current named session. <code>cq</code> resumes with the same session UUID automatically.</td></tr><tr><td><code>/session-distill</code></td><td>session distill, session summary, distill</td><td>Distill the current session into persistent knowledge. Extracts decisions, patterns, and insights into the knowledge base.</td></tr></tbody></table><h2 id="research-documents" tabindex="-1">Research &amp; Documents <a class="header-anchor" href="#research-documents" aria-label="Permalink to &quot;Research &amp; Documents&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Skill</th><th>Triggers</th><th>Description</th></tr></thead><tbody><tr><td><code>/c9-init</code></td><td>c9-init, c9 initialize</td><td>Initialize a new C9 research project. Creates <code>state.yaml</code> with metric, convergence conditions, and Hub URL.</td></tr><tr><td><code>/c9-loop</code></td><td>c9-loop</td><td>Main loop driver — reads current phase from <code>state.yaml</code> and auto-executes next step.</td></tr><tr><td><code>/c9-survey</code></td><td>c9-survey</td><td>Survey latest arXiv papers + SOTA benchmarks using Gemini Google Search grounding.</td></tr><tr><td><code>/c9-conference</code></td><td>c9-conference</td><td>Claude (Opus) + Gemini (Pro) debate mode — research conference simulation.</td></tr><tr><td><code>/c9-steer</code></td><td>c9-steer</td><td>Change phase and update reason without editing <code>state.yaml</code> directly.</td></tr><tr><td><code>/c9-report</code></td><td>c9-report</td><td>Collect experiment results from remote server via distributed worker.</td></tr><tr><td><code>/c9-finish</code></td><td>c9-finish</td><td>Save best model + document results when research loop completes.</td></tr><tr><td><code>/c9-deploy</code></td><td>c9-deploy</td><td>Deploy best model to edge server. Can run independently of <code>/c9-finish</code>.</td></tr><tr><td><code>/research-loop</code></td><td>research loop</td><td>Paper-experiment improvement loop. Iterates review → plan → experiment → re-review until target quality reached.</td></tr><tr><td><code>/experiment-workflow</code></td><td>experiment workflow, experiment lifecycle</td><td>End-to-end experiment lifecycle management: data prep → train → eval → record.</td></tr><tr><td><code>/c2-paper-review</code></td><td>paper review, academic review</td><td><em>(Deprecated — use <code>/review</code> instead.)</em></td></tr></tbody></table><h2 id="development" tabindex="-1">Development <a class="header-anchor" href="#development" aria-label="Permalink to &quot;Development&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Skill</th><th>Triggers</th><th>Description</th></tr></thead><tbody><tr><td><code>/tdd-cycle</code></td><td>TDD, test-driven, RED-GREEN-REFACTOR</td><td>TDD cycle guide. RED-GREEN-REFACTOR sequence for test-driven development.</td></tr><tr><td><code>/debugging</code></td><td>debug, debugging, bug tracking</td><td>Systematic debugging. Reproduce → hypothesis → isolate → fix → verify sequence.</td></tr><tr><td><code>/spec-first</code></td><td>spec-first, spec first, design doc</td><td>Spec-First development guide. Write spec doc before code.</td></tr><tr><td><code>/incident-response</code></td><td>incident, outage, server down, error rate surge</td><td>Production incident response workflow. Triage → diagnose → mitigate → postmortem.</td></tr></tbody></table><h2 id="meta-utilities" tabindex="-1">Meta &amp; Utilities <a class="header-anchor" href="#meta-utilities" aria-label="Permalink to &quot;Meta &amp; Utilities&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Skill</th><th>Triggers</th><th>Description</th></tr></thead><tbody><tr><td><code>/craft</code></td><td>craft, create skill, create rule</td><td>Interactively create skills, agents, rules, and CLAUDE.md customizations.</td></tr><tr><td><code>/help</code></td><td>help</td><td>Quick reference for skills, agents, and MCP tools. Decision tree + keyword search across all 42 skills.</td></tr><tr><td><code>/clear</code></td><td>clear</td><td>Reset C4 state for debugging. Clears tasks, events, locks in <code>.c4/</code> with optional config preservation.</td></tr><tr><td><code>/init</code></td><td>init, initialize</td><td>Initialize C4 in current project. Detects installation path, runs <code>cq claude/cursor/codex</code>.</td></tr><tr><td><code>/claude-md-improver</code></td><td>improve CLAUDE.md, claude-md, improve instructions</td><td>Analyze and improve the project&#39;s CLAUDE.md. Structure check, build/test commands, agent rules.</td></tr><tr><td><code>/skill-tester</code></td><td>skill tester, skill eval, eval</td><td>Test and evaluate skill quality. Generate eval cases, run classification trials, score trigger accuracy.</td></tr><tr><td><code>/pr-review</code></td><td>create PR, PR checklist, pull request</td><td>PR/MR creation checklist and review guide. Auto-validates before merge.</td></tr><tr><td><code>/release</code></td><td>release</td><td>Generate CHANGELOG from git history. Conventional Commits analysis, semantic version suggestion, tag creation.</td></tr><tr><td><code>/standby</code></td><td>standby, wait, worker mode</td><td>Convert session into persistent distributed worker via Supabase. Waits for jobs, executes, reports back. <em>full tier only</em></td></tr><tr><td><code>/interview</code></td><td>interview</td><td>Deep exploratory requirements interview. Acts as senior PM/architect to discover hidden requirements and edge cases.</td></tr></tbody></table><hr><h2 id="skill-health" tabindex="-1">Skill Health <a class="header-anchor" href="#skill-health" aria-label="Permalink to &quot;Skill Health&quot;">​</a></h2><blockquote><p>Requires <code>connected</code> or <code>full</code> tier (LLM Gateway needed for haiku classification).</p></blockquote><p>Measure and monitor whether skills trigger correctly — ensuring Claude classifies user prompts accurately before and after changes.</p><table tabindex="0"><thead><tr><th>MCP Tool</th><th>Description</th></tr></thead><tbody><tr><td><code>c4_skill_eval_run</code></td><td>Run k-trial haiku classification on a skill&#39;s EVAL.md test cases. Returns <code>trigger_accuracy</code>.</td></tr><tr><td><code>c4_skill_eval_generate</code></td><td>Generate EVAL.md test cases (positive + negative prompts) for a skill using haiku.</td></tr><tr><td><code>c4_skill_eval_status</code></td><td>Show trigger accuracy summary for all evaluated skills. <code>ok</code> = ≥ 0.90.</td></tr></tbody></table><p><code>cq doctor</code> includes a <code>skill-health</code> check that warns when any skill drops below the 0.90 threshold.</p><hr><h2 id="machine-readable" tabindex="-1">Machine-readable <a class="header-anchor" href="#machine-readable" aria-label="Permalink to &quot;Machine-readable&quot;">​</a></h2><p>Download as JSONL for programmatic use:</p><div class="language-sh vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://playidea-lab.github.io/cq/api/skills.jsonl</span></span></code></pre></div>',28)])])}const m=t(o,[["render",i]]);export{u as __pageData,m as default};
